_patients AS (
SELECT DISTINCT patient_ref AS patient_id FROM resources WHERE patient_ref IS NOT NULL
),
_patient_demographics AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, CAST(fhirpath_date(r.resource, 'birthDate') AS DATE) AS birth_date FROM resources r WHERE r.resourceType = 'Patient'
),
"Encounter: Contact or Office Visit" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, struct_pack(target := r.resourceType || '/' || fhirpath_text(r.resource, 'id'), attribute := CAST(NULL AS VARCHAR), value := CAST(NULL AS VARCHAR), operator := 'exists', threshold := '[Encounter: "Contact or Office Visit"]', trace := CAST([] AS VARCHAR[])) AS _audit_item FROM resources r WHERE r.resourceType = 'Encounter' AND EXISTS (SELECT 1 FROM (SELECT unnest(flatten(COALESCE(list_transform(COALESCE(from_json(json_extract(r.resource::JSON, '$.type'), '["JSON"]'), CAST([] AS JSON[])), _cc -> COALESCE(from_json(json_extract(_cc, '$.coding'), '["JSON"]'), CAST([] AS JSON[]))), CAST([] AS JSON[][])))) AS _c) _inv INNER JOIN _vs_0 ON _vs_0._vs_code = json_extract_string(_c, '$.code') AND (_vs_0._vs_system = '' OR _vs_0._vs_system = json_extract_string(_c, '$.system')))
),
"Condition: Hospice Diagnosis (qicore-condition-encounter-diagnosis)" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, struct_pack(target := r.resourceType || '/' || fhirpath_text(r.resource, 'id'), attribute := CAST(NULL AS VARCHAR), value := CAST(NULL AS VARCHAR), operator := 'exists', threshold := '[ConditionEncounterDiagnosis: "Hospice Diagnosis"]', trace := CAST([] AS VARCHAR[])) AS _audit_item FROM resources r WHERE r.resourceType = 'Condition' AND EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(r.resource::JSON, '$.code.coding'), '["JSON"]'),CAST([] AS JSON[]))) AS _c) _inv INNER JOIN _vs_5 ON _vs_5._vs_code = json_extract_string(_c, '$.code') AND (_vs_5._vs_system = '' OR _vs_5._vs_system = json_extract_string(_c, '$.system'))) AND list_contains(from_json(json_extract(r.resource, '$.meta.profile'), '["VARCHAR"]'), 'http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-condition-encounter-diagnosis')
),
"Observation: PHQ 9 and PHQ 9M Tools" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, fhirpath_text(r.resource, 'status') AS status, fhirpath_text(r.resource, 'value') AS value, struct_pack(target := r.resourceType || '/' || fhirpath_text(r.resource, 'id'), attribute := CAST(NULL AS VARCHAR), value := CAST(NULL AS VARCHAR), operator := 'exists', threshold := '[ObservationScreeningAssessment: "PHQ 9 and PHQ 9M Tools"]', trace := CAST([] AS VARCHAR[])) AS _audit_item FROM resources r WHERE r.resourceType = 'Observation' AND EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(r.resource::JSON, '$.code.coding'), '["JSON"]'),CAST([] AS JSON[]))) AS _c) _inv INNER JOIN _vs_13 ON _vs_13._vs_code = json_extract_string(_c, '$.code') AND (_vs_13._vs_system = '' OR _vs_13._vs_system = json_extract_string(_c, '$.system')))
),
"Observation: Hospice care [Minimum Data Set]" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, struct_pack(target := r.resourceType || '/' || fhirpath_text(r.resource, 'id'), attribute := CAST(NULL AS VARCHAR), value := CAST(NULL AS VARCHAR), operator := 'exists', threshold := '[ObservationScreeningAssessment: "Hospice care [Minimum Data Set]"]', trace := CAST([] AS VARCHAR[])) AS _audit_item FROM resources r WHERE r.resourceType = 'Observation' AND EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(r.resource::JSON, '$.code.coding'), '["JSON"]'), from_json(json_extract(r.resource::JSON, '$.code[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://loinc.org' AND json_extract_string(c, '$.code') = '45755-6')
),
"Condition: Dysthymia (qicore-condition-encounter-diagnosis)" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, struct_pack(target := r.resourceType || '/' || fhirpath_text(r.resource, 'id'), attribute := CAST(NULL AS VARCHAR), value := CAST(NULL AS VARCHAR), operator := 'exists', threshold := '[ConditionEncounterDiagnosis: "Dysthymia"]', trace := CAST([] AS VARCHAR[])) AS _audit_item FROM resources r WHERE r.resourceType = 'Condition' AND EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(r.resource::JSON, '$.code.coding'), '["JSON"]'),CAST([] AS JSON[]))) AS _c) _inv INNER JOIN _vs_12 ON _vs_12._vs_code = json_extract_string(_c, '$.code') AND (_vs_12._vs_system = '' OR _vs_12._vs_system = json_extract_string(_c, '$.system'))) AND list_contains(from_json(json_extract(r.resource, '$.meta.profile'), '["VARCHAR"]'), 'http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-condition-encounter-diagnosis')
),
"Condition: Major Depression Including Remission (qicore-condition-problems-health-concerns)" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, struct_pack(target := r.resourceType || '/' || fhirpath_text(r.resource, 'id'), attribute := CAST(NULL AS VARCHAR), value := CAST(NULL AS VARCHAR), operator := 'exists', threshold := '[ConditionProblemsHealthConcerns: "Major Depression Including Remission"]', trace := CAST([] AS VARCHAR[])) AS _audit_item FROM resources r WHERE r.resourceType = 'Condition' AND EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(r.resource::JSON, '$.code.coding'), '["JSON"]'),CAST([] AS JSON[]))) AS _c) _inv INNER JOIN _vs_15 ON _vs_15._vs_code = json_extract_string(_c, '$.code') AND (_vs_15._vs_system = '' OR _vs_15._vs_system = json_extract_string(_c, '$.system'))) AND list_contains(from_json(json_extract(r.resource, '$.meta.profile'), '["VARCHAR"]'), 'http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-condition-problems-health-concerns')
),
"Condition: Schizophrenia or Psychotic Disorder (qicore-condition-encounter-diagnosis)" AS (
