),
"Condition: Pervasive Developmental Disorder (qicore-condition-encounter-diagnosis)" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, struct_pack(target := r.resourceType || '/' || fhirpath_text(r.resource, 'id'), attribute := CAST(NULL AS VARCHAR), value := CAST(NULL AS VARCHAR), operator := 'exists', threshold := '[ConditionEncounterDiagnosis: "Pervasive Developmental Disorder"]', trace := CAST([] AS VARCHAR[])) AS _audit_item FROM resources r WHERE r.resourceType = 'Condition' AND EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(r.resource::JSON, '$.code.coding'), '["JSON"]'),CAST([] AS JSON[]))) AS _c) _inv INNER JOIN _vs_4 ON _vs_4._vs_code = json_extract_string(_c, '$.code') AND (_vs_4._vs_system = '' OR _vs_4._vs_system = json_extract_string(_c, '$.system'))) AND list_contains(from_json(json_extract(r.resource, '$.meta.profile'), '["VARCHAR"]'), 'http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-condition-encounter-diagnosis')
