),
"SDE.SDE Ethnicity" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-ethnicity'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_E -> to_json(struct_pack(codes := jsonConcat([fhirpath_text(_lt_E, 'ombCategory')], fhirpath_text(_lt_E, 'detailed')), display := fhirpath_text(_lt_E, 'text')))) AS resource FROM _patients AS p
),
"SDE.SDE Payer" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource, _inner._audit_item AS _audit_item FROM (SELECT patient_id, to_json(struct_pack(code := fhirpath_text(Payer.resource, 'type'), period := fhirpath_text(Payer.resource, 'period'))) AS _resource_data, Payer._audit_item AS _audit_item FROM "Coverage: Payer Type" AS Payer) AS _inner
),
"SDE.SDE Race" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-race'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_R -> to_json(struct_pack(codes := jsonConcat(fhirpath_text(_lt_R, 'ombCategory'), fhirpath_text(_lt_R, 'detailed')), display := fhirpath_text(_lt_R, 'text')))) AS resource FROM _patients AS p
),
"SDE.SDE Sex" AS (
SELECT p.patient_id, (SELECT CASE WHEN (SELECT json_extract_string(e, '$.valueCode') FROM (SELECT unnest(COALESCE(from_json(json_extract((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)::JSON, '$.extension'), '["JSON"]'), CAST([] AS JSON[]))) AS e) _ext_t WHERE json_extract_string(e, '$.url') = 'http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex' LIMIT 1) = '248153007' THEN 'http://snomed.info/sct|248153007' WHEN (SELECT json_extract_string(e, '$.valueCode') FROM (SELECT unnest(COALESCE(from_json(json_extract((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)::JSON, '$.extension'), '["JSON"]'), CAST([] AS JSON[]))) AS e) _ext_t WHERE json_extract_string(e, '$.url') = 'http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex' LIMIT 1) = '248152002' THEN 'http://snomed.info/sct|248152002' ELSE NULL END) AS value FROM _patients AS p
),
"Denominator Identification Period" AS (
SELECT p.patient_id, intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 14.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 2.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, FALSE) AS value FROM _patients AS p
),
"Depression Assessments Greater Than 9" AS (
SELECT * FROM "Observation: PHQ 9 and PHQ 9M Tools" AS DepressionAssessment WHERE TRY_CAST(CASE WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'value')), '{') THEN json_extract_string(fhirpath_text(DepressionAssessment.resource, 'value'), '$.value') ELSE fhirpath_text(DepressionAssessment.resource, 'value') END AS DOUBLE) > 9 AND array_contains(['final', 'amended', 'corrected'], DepressionAssessment.status)
),
"Depression Diagnoses" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Condition: Major Depression Including Remission (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Major Depression Including Remission (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Dysthymia (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Dysthymia (qicore-condition-encounter-diagnosis)") AS Depression WHERE (EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(Depression.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(Depression.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://terminology.hl7.org/CodeSystem/condition-clinical' AND json_extract_string(c, '$.code') = 'active') OR EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(Depression.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(Depression.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://terminology.hl7.org/CodeSystem/condition-clinical' AND json_extract_string(c, '$.code') = 'recurrence') OR EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(Depression.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(Depression.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://terminology.hl7.org/CodeSystem/condition-clinical' AND json_extract_string(c, '$.code') = 'relapse')) AND EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(Depression.resource::JSON, '$.verificationStatus.coding'), '["JSON"]'), from_json(json_extract(Depression.resource::JSON, '$.verificationStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://terminology.hl7.org/CodeSystem/condition-ver-status' AND json_extract_string(c, '$.code') = 'confirmed')
),
"Depression Encounter" AS (
SELECT * FROM "Encounter: Contact or Office Visit" AS ValidEncounter WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Depression Diagnoses") AS Depression WHERE intervalOverlaps(fhirpath_text(ValidEncounter.resource, 'period'), CASE WHEN fhirpath_text(Depression.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(Depression.resource, 'onsetDateTime'), fhirpath_text(Depression.resource, 'onsetPeriod.start'), fhirpath_text(Depression.resource, 'recordedDate')), fhirpath_text(Depression.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(Depression.resource, 'onsetDateTime'), fhirpath_text(Depression.resource, 'onsetPeriod.start'), fhirpath_text(Depression.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(Depression.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(Depression.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE (json_extract_string(c, '$.code') = 'active' OR json_extract_string(c, '$.code') = 'recurrence' OR json_extract_string(c, '$.code') = 'relapse')) THEN intervalFromBounds(COALESCE(fhirpath_text(Depression.resource, 'onsetDateTime'), fhirpath_text(Depression.resource, 'onsetPeriod.start'), fhirpath_text(Depression.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(Depression.resource, 'onsetDateTime'), fhirpath_text(Depression.resource, 'onsetPeriod.start'), fhirpath_text(Depression.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AND CAST(intervalEnd(fhirpath_text(ValidEncounter.resource, 'period')) AS DATE) BETWEEN CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = ValidEncounter.patient_id LIMIT 1)) AS DATE) AND COALESCE(CAST(intervalEnd((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = ValidEncounter.patient_id LIMIT 1)) AS DATE), CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = ValidEncounter.patient_id LIMIT 1)) AS DATE)) AND fhirpath_text(ValidEncounter.resource, 'status') = 'finished' AND Depression.patient_id = ValidEncounter.patient_id)
),
"Index Depression Assessment" AS (
SELECT p.patient_id, (SELECT resource FROM "Depression Assessments Greater Than 9" AS DepressionAssessment WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Depression Encounter") AS DepressionEncounter WHERE CAST(intervalStart(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) >= CAST(CAST(dateSubtractQuantity(CAST(intervalStart(fhirpath_text(DepressionEncounter.resource, 'period')) AS VARCHAR), '{"value": 7.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS DATE) AS DATE) AND CAST(intervalEnd(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) <= CAST(intervalEnd(fhirpath_text(DepressionEncounter.resource, 'period')) AS DATE) AND DepressionEncounter.patient_id = DepressionAssessment.patient_id) AND DepressionAssessment.patient_id = p.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END) ASC NULLS LAST, json_extract_string(DepressionAssessment.resource, '$.id') ASC NULLS LAST LIMIT 1) AS resource FROM _patients AS p
),
"Initial Population" AS (
