ntervalStart(CASE WHEN fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective')), '{') THEN fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective') ELSE intervalFromBounds(fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective'), fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective'), TRUE, TRUE) END) AS DATE)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST(intervalStart(CASE WHEN fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective')), '{') THEN fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective') ELSE intervalFromBounds(fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective'), fhirpath_text((SELECT sub.resource FROM "Index Depression Assessment" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'effective'), TRUE, TRUE) END) AS DATE)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) THEN 1 ELSE 0 END >= 12
),
"Denominator" AS (
