),
"Has Hospice Services in the Measure Assessment Period" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "Measure Assessment Period" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM "Encounter: Encounter Inpatient" AS InpatientEncounter WHERE InpatientEncounter.patient_id = p.patient_id AND (EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(InpatientEncounter.resource::JSON, '$.hospitalization.dischargeDisposition.coding'), '["JSON"]'), from_json(json_extract(InpatientEncounter.resource::JSON, '$.hospitalization[0].dischargeDisposition.coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://snomed.info/sct' AND json_extract_string(c, '$.code') = '428361000124107') OR EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(InpatientEncounter.resource::JSON, '$.hospitalization.dischargeDisposition.coding'), '["JSON"]'), from_json(json_extract(InpatientEncounter.resource::JSON, '$.hospitalization[0].dischargeDisposition.coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://snomed.info/sct' AND json_extract_string(c, '$.code') = '428371000124100')) AND CAST(intervalEnd(fhirpath_text(InpatientEncounter.resource, 'period')) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE)) AND fhirpath_text(InpatientEncounter.resource, 'status') = 'finished') OR EXISTS (SELECT * FROM "Encounter: Hospice Encounter" AS HospiceEncounter WHERE HospiceEncounter.patient_id = p.patient_id AND CAST(intervalStart(fhirpath_text(HospiceEncounter.resource, 'period')) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(fhirpath_text(HospiceEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE) AND NOT array_contains(['cancelled', 'entered-in-error', 'unknown'], fhirpath_text(HospiceEncounter.resource, 'status'))) OR EXISTS (SELECT * FROM "Observation: Hospice care [Minimum Data Set]" AS HospiceAssessment WHERE HospiceAssessment.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(HospiceAssessment.resource::JSON, '$.valueCodeableConcept.coding'), '["JSON"]'), from_json(json_extract(HospiceAssessment.resource::JSON, '$.value.coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://snomed.info/sct' AND json_extract_string(c, '$.code') = '373066001') AND CAST(intervalStart(CASE WHEN fhirpath_text(HospiceAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospiceAssessment.resource, 'effective')), '{') THEN fhirpath_text(HospiceAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HospiceAssessment.resource, 'effective'), fhirpath_text(HospiceAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(HospiceAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospiceAssessment.resource, 'effective')), '{') THEN fhirpath_text(HospiceAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HospiceAssessment.resource, 'effective'), fhirpath_text(HospiceAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE) AND array_contains(['final', 'amended', 'corrected'], fhirpath_text(HospiceAssessment.resource, 'status'))) OR EXISTS (SELECT * FROM "ServiceRequest: Hospice Care Ambulatory" AS HospiceOrder WHERE HospiceOrder.patient_id = p.patient_id AND CAST(fhirpath_text(HospiceOrder.resource, 'authoredOn') AS DATE) >= CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS DATE) AND CAST(fhirpath_text(HospiceOrder.resource, 'authoredOn') AS DATE) <= CAST(intervalEnd(j1.value) AS DATE) AND array_contains(['active', 'completed'], fhirpath_text(HospiceOrder.resource, 'status')) AND array_contains(['order', 'original-order', 'reflex-order', 'filler-order', 'instance-order'], fhirpath_text(HospiceOrder.resource, 'intent')) AND fhirpath_text(HospiceOrder.resource, 'doNotPerform') IS NOT TRUE) OR EXISTS (SELECT * FROM "Procedure: Hospice Care Ambulatory" AS HospicePerformed WHERE HospicePerformed.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(HospicePerformed.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospicePerformed.resource, 'performed')), '{') THEN fhirpath_text(HospicePerformed.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(HospicePerformed.resource, 'performed'), fhirpath_text(HospicePerformed.resource, 'performed'), TRUE, TRUE) END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(HospicePerformed.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospicePerformed.resource, 'performed')), '{') THEN fhirpath_text(HospicePerformed.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(HospicePerformed.resource, 'performed'), fhirpath_text(HospicePerformed.resource, 'performed'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE) AND NOT array_contains(['not-done', 'entered-in-error', 'unknown'], fhirpath_text(HospicePerformed.resource, 'status'))) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Hospice Diagnosis (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Hospice Diagnosis (qicore-condition-encounter-diagnosis)") AS HospiceCareDiagnosis WHERE HospiceCareDiagnosis.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(HospiceCareDiagnosis.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(HospiceCareDiagnosis.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE (json_extract_string(c, '$.code') = 'active' OR json_extract_string(c, '$.code') = 'recurrence' OR json_extract_string(c, '$.code') = 'relapse')) THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(HospiceCareDiagnosis.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(HospiceCareDiagnosis.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE (json_extract_string(c, '$.code') = 'active' OR json_extract_string(c, '$.code') = 'recurrence' OR json_extract_string(c, '$.code') = 'relapse')) THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE) AND (EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(HospiceCareDiagnosis.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(HospiceCareDiagnosis.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://terminology.hl7.org/CodeSystem/condition-clinical' AND json_extract_string(c, '$.code') = 'active') OR EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(HospiceCareDiagnosis.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(HospiceCareDiagnosis.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://terminology.hl7.org/CodeSystem/condition-clinical' AND json_extract_string(c, '$.code') = 'recurrence') OR EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(HospiceCareDiagnosis.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(HospiceCareDiagnosis.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://terminology.hl7.org/CodeSystem/condition-clinical' AND json_extract_string(c, '$.code') = 'relapse')) AND EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(HospiceCareDiagnosis.resource::JSON, '$.verificationStatus.coding'), '["JSON"]'), from_json(json_extract(HospiceCareDiagnosis.resource::JSON, '$.verificationStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://terminology.hl7.org/CodeSystem/condition-ver-status' AND json_extract_string(c, '$.code') = 'confirmed'))
),
"Has Mental Health Disorder Diagnoses" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "Measure Assessment Period" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Bipolar Disorder (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Bipolar Disorder (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Personality Disorder Emotionally Labile (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Personality Disorder Emotionally Labile (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Schizophrenia or Psychotic Disorder (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Schizophrenia or Psychotic Disorder (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Pervasive Developmental Disorder (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Pervasive Developmental Disorder (qicore-condition-encounter-diagnosis)") AS MentalHealthDisorderDiagnoses WHERE MentalHealthDisorderDiagnoses.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetDateTime'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetPeriod.start'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'recordedDate')), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetDateTime'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetPeriod.start'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(MentalHealthDisorderDiagnoses.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(MentalHealthDisorderDiagnoses.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE (json_extract_string(c, '$.code') = 'active' OR json_extract_string(c, '$.code') = 'recurrence' OR json_extract_string(c, '$.code') = 'relapse')) THEN intervalFromBounds(COALESCE(fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetDateTime'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetPeriod.start'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetDateTime'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'onsetPeriod.start'), fhirpath_text(MentalHealthDisorderDiagnoses.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= CAST(intervalEnd(j1.value) AS DATE) AND (EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(MentalHealthDisorderDiagnoses.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(MentalHealthDisorderDiagnoses.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://terminology.hl7.org/CodeSystem/condition-clinical' AND json_extract_string(c, '$.code') = 'active') OR EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(MentalHealthDisorderDiagnoses.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(MentalHealthDisorderDiagnoses.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://terminology.hl7.org/CodeSystem/condition-clinical' AND json_extract_string(c, '$.code') = 'recurrence') OR EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(MentalHealthDisorderDiagnoses.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(MentalHealthDisorderDiagnoses.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://terminology.hl7.org/CodeSystem/condition-clinical' AND json_extract_string(c, '$.code') = 'relapse')) AND EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(MentalHealthDisorderDiagnoses.resource::JSON, '$.verificationStatus.coding'), '["JSON"]'), from_json(json_extract(MentalHealthDisorderDiagnoses.resource::JSON, '$.verificationStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://terminology.hl7.org/CodeSystem/condition-ver-status' AND json_extract_string(c, '$.code') = 'confirmed'))
),
"Has Palliative Care in the Measure Assessment Period" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "Measure Assessment Period" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM "Observation: Functional Assessment of Chronic Illness Therapy - Palliative Care Questionnaire (FACIT-Pal)" AS PalliativeAssessment WHERE PalliativeAssessment.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(PalliativeAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PalliativeAssessment.resource, 'effective')), '{') THEN fhirpath_text(PalliativeAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(PalliativeAssessment.resource, 'effective'), fhirpath_text(PalliativeAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(PalliativeAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PalliativeAssessment.resource, 'effective')), '{') THEN fhirpath_text(PalliativeAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(PalliativeAssessment.resource, 'effective'), fhirpath_text(PalliativeAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE) AND array_contains(['final', 'amended', 'corrected'], fhirpath_text(PalliativeAssessment.resource, 'status'))) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Palliative Care Diagnosis (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Palliative Care Diagnosis (qicore-condition-encounter-diagnosis)") AS PalliativeDiagnosis WHERE PalliativeDiagnosis.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(PalliativeDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(PalliativeDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PalliativeDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PalliativeDiagnosis.resource, 'recordedDate')), fhirpath_text(PalliativeDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(PalliativeDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PalliativeDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PalliativeDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(PalliativeDiagnosis.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(PalliativeDiagnosis.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE (json_extract_string(c, '$.code') = 'active' OR json_extract_string(c, '$.code') = 'recurrence' OR json_extract_string(c, '$.code') = 'relapse')) THEN intervalFromBounds(COALESCE(fhirpath_text(PalliativeDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PalliativeDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PalliativeDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(PalliativeDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PalliativeDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PalliativeDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(PalliativeDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(PalliativeDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PalliativeDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PalliativeDiagnosis.resource, 'recordedDate')), fhirpath_text(PalliativeDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(PalliativeDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PalliativeDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PalliativeDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(PalliativeDiagnosis.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(PalliativeDiagnosis.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE (json_extract_string(c, '$.code') = 'active' OR json_extract_string(c, '$.code') = 'recurrence' OR json_extract_string(c, '$.code') = 'relapse')) THEN intervalFromBounds(COALESCE(fhirpath_text(PalliativeDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PalliativeDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PalliativeDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(PalliativeDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PalliativeDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PalliativeDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE) AND (EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(PalliativeDiagnosis.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(PalliativeDiagnosis.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://terminology.hl7.org/CodeSystem/condition-clinical' AND json_extract_string(c, '$.code') = 'active') OR EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(PalliativeDiagnosis.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(PalliativeDiagnosis.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://terminology.hl7.org/CodeSystem/condition-clinical' AND json_extract_string(c, '$.code') = 'recurrence') OR EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(PalliativeDiagnosis.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(PalliativeDiagnosis.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://terminology.hl7.org/CodeSystem/condition-clinical' AND json_extract_string(c, '$.code') = 'relapse')) AND EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(PalliativeDiagnosis.resource::JSON, '$.verificationStatus.coding'), '["JSON"]'), from_json(json_extract(PalliativeDiagnosis.resource::JSON, '$.verificationStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE json_extract_string(c, '$.system') = 'http://terminology.hl7.org/CodeSystem/condition-ver-status' AND json_extract_string(c, '$.code') = 'confirmed')) OR EXISTS (SELECT * FROM "Encounter: Palliative Care Encounter" AS PalliativeEncounter WHERE PalliativeEncounter.patient_id = p.patient_id AND CAST(intervalStart(fhirpath_text(PalliativeEncounter.resource, 'period')) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(fhirpath_text(PalliativeEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE) AND fhirpath_text(PalliativeEncounter.resource, 'status') = 'finished') OR EXISTS (SELECT * FROM "Procedure: Palliative Care Intervention" AS PalliativeIntervention WHERE PalliativeIntervention.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(PalliativeIntervention.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PalliativeIntervention.resource, 'performed')), '{') THEN fhirpath_text(PalliativeIntervention.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(PalliativeIntervention.resource, 'performed'), fhirpath_text(PalliativeIntervention.resource, 'performed'), TRUE, TRUE) END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(PalliativeIntervention.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PalliativeIntervention.resource, 'performed')), '{') THEN fhirpath_text(PalliativeIntervention.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(PalliativeIntervention.resource, 'performed'), fhirpath_text(PalliativeIntervention.resource, 'performed'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(intervalStart((SELECT sub.value FROM "Denominator Identification Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS VARCHAR), CAST(intervalEnd(j1.value) AS VARCHAR), TRUE, TRUE)) AS DATE) AND NOT array_contains(['not-done', 'entered-in-error', 'unknown'], fhirpath_text(PalliativeIntervention.resource, 'status')))
),
"Numerator" AS (
SELECT p.patient_id FROM _patients AS p WHERE TRY_CAST(CASE WHEN starts_with(LTRIM(fhirpath_text((SELECT resource FROM "Observation: PHQ 9 and PHQ 9M Tools" AS DepressionAssessment WHERE CAST(CAST(intervalStart(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) AS DATE) >= CAST(intervalStart((SELECT sub.value FROM "Measure Assessment Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS DATE) AND CAST(CAST(intervalStart(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) AS DATE) < CAST(intervalEnd((SELECT sub.value FROM "Measure Assessment Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS DATE) AND array_contains(['final', 'amended', 'corrected'], fhirpath_text(DepressionAssessment.resource, 'status')) AND DepressionAssessment.patient_id = p.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END) DESC NULLS FIRST, json_extract_string(DepressionAssessment.resource, '$.id') ASC NULLS LAST LIMIT 1), 'value')), '{') THEN json_extract_string(fhirpath_text((SELECT resource FROM "Observation: PHQ 9 and PHQ 9M Tools" AS DepressionAssessment WHERE CAST(CAST(intervalStart(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) AS DATE) >= CAST(intervalStart((SELECT sub.value FROM "Measure Assessment Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS DATE) AND CAST(CAST(intervalStart(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) AS DATE) < CAST(intervalEnd((SELECT sub.value FROM "Measure Assessment Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS DATE) AND array_contains(['final', 'amended', 'corrected'], fhirpath_text(DepressionAssessment.resource, 'status')) AND DepressionAssessment.patient_id = p.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END) DESC NULLS FIRST, json_extract_string(DepressionAssessment.resource, '$.id') ASC NULLS LAST LIMIT 1), 'value'), '$.value') ELSE fhirpath_text((SELECT resource FROM "Observation: PHQ 9 and PHQ 9M Tools" AS DepressionAssessment WHERE CAST(CAST(intervalStart(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) AS DATE) >= CAST(intervalStart((SELECT sub.value FROM "Measure Assessment Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS DATE) AND CAST(CAST(intervalStart(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) AS DATE) < CAST(intervalEnd((SELECT sub.value FROM "Measure Assessment Period" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS DATE) AND array_contains(['final', 'amended', 'corrected'], fhirpath_text(DepressionAssessment.resource, 'status')) AND DepressionAssessment.patient_id = p.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(DepressionAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(DepressionAssessment.resource, 'effective')), '{') THEN fhirpath_text(DepressionAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(DepressionAssessment.resource, 'effective'), fhirpath_text(DepressionAssessment.resource, 'effective'), TRUE, TRUE) END) DESC NULLS FIRST, json_extract_string(DepressionAssessment.resource, '$.id') ASC NULLS LAST LIMIT 1), 'value') END AS DOUBLE) < 5
),
"Patient Expired" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "Measure Assessment Period" AS j1 ON j1.patient_id = p.patient_id WHERE CAST(fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'deceased') AS TIMESTAMP) <= CAST(intervalEnd(j1.value) AS DATE)
),
"Denominator Exclusions" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Has Hospice Services in the Measure Assessment Period" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Palliative Care in the Measure Assessment Period" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Patient Expired" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Mental Health Disorder Diagnoses" AS sub WHERE sub.patient_id = p.patient_id)
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
)
SELECT p.patient_id, compact_audit(struct_pack(result := CASE WHEN "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END, evidence := [])) AS "Initial Population", compact_audit(struct_pack(result := CASE WHEN "Denominator".patient_id IS NOT NULL AND "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END, evidence := [])) AS Denominator, compact_audit(struct_pack(result := CASE WHEN "Denominator Exclusions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END, evidence := [])) AS "Denominator Exclusions", compact_audit(struct_pack(result := CASE WHEN "Numerator".patient_id IS NOT NULL AND "Initial Population".patient_id IS NOT NULL AND "Denominator Exclusions".patient_id IS NULL THEN TRUE ELSE FALSE END, evidence := [])) AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusions" ON p.patient_id = "Denominator Exclusions".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
